import React, { useEffect, useState } from "react";
import "./Admin.css";

const Admin = () => {
  const [stats, setStats] = useState([]);
  const [news, setNews] = useState([]);

  const [form, setForm] = useState({
    title: "",
    description: "",
    location: "",
    date: "",
    category: "IT",
    image: ""
  });

  const [newsForm, setNewsForm] = useState({
    title: "",
    content: "",
    date: ""
  });

  // 🔥 редактирование события
  const [editingEvent, setEditingEvent] = useState(null);

  // =========================
  // 📊 СТАТИСТИКА
  // =========================
  const loadStats = () => {
    fetch("http://localhost:5000/admin/stats")
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) setStats(data);
        else setStats([]);
      });
  };

  const loadNews = () => {
    fetch("http://localhost:5000/admin/news")
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) setNews(data);
        else setNews([]);
      });
  };

  useEffect(() => {
    loadStats();
    loadNews();
  }, []);

  // =========================
  // 🗑 УДАЛЕНИЕ
  // =========================
  const handleDelete = async (id) => {
    if (!window.confirm("Видалити подію?")) return;

    const res = await fetch(`http://localhost:5000/events/${id}`, {
      method: "DELETE"
    });

    if (res.ok) {
      setStats(prev => prev.filter(e => e.id !== id));
    }
  };

  const handleDeleteNews = async (id) => {
    if (!window.confirm("Видалити новину?")) return;

    const res = await fetch(`http://localhost:5000/admin/news/${id}`, {
      method: "DELETE"
    });

    if (res.ok) {
      setNews(prev => prev.filter(n => n.id !== id));
    }
  };

  // =========================
  // ➕ СОБЫТИЕ
  // =========================
  const handleSubmit = async (e) => {
    e.preventDefault();

    const res = await fetch("http://localhost:5000/admin/events", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form)
    });

    if (res.ok) {
      alert("Подія створена 🎉");

      setForm({
        title: "",
        description: "",
        location: "",
        date: "",
        category: "IT",
        image: ""
      });

      loadStats();
    }
  };

  // =========================
  // ✏️ ОБНОВЛЕНИЕ СОБЫТИЯ
  // =========================
  const handleUpdateEvent = async (e) => {
    e.preventDefault();

    const res = await fetch(
      `http://localhost:5000/admin/events/${editingEvent.id}`,
      {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(editingEvent)
      }
    );

    if (res.ok) {
      alert("Оновлено ✏️");
      setEditingEvent(null);
      loadStats();
    }
  };

  // =========================
  // 📰 НОВОСТЬ
  // =========================
  const handleAddNews = async (e) => {
    e.preventDefault();

    const res = await fetch("http://localhost:5000/admin/news", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(newsForm)
    });

    if (res.ok) {
      alert("Новину додано 📰");

      setNewsForm({
        title: "",
        content: "",
        date: ""
      });

      loadNews();
    }
  };

  return (
    <div className="admin-page">

      <h1>Адмін панель</h1>

      {/* 📊 СОБЫТИЯ */}
      <div className="admin-stats">
        <h2>Події</h2>

        {stats.length > 0 ? (
          stats.map(event => (
            <div key={event.id} className="stat-card">

              <div>
                <h3>{event.title}</h3>
                <p>Реєстрацій: {event.registrations}</p>
              </div>

              <div>
                <button
                  className="edit-btn"
                  onClick={() => setEditingEvent(event)}
                >
                  ✏️
                </button>

                <button
                  className="delete-btn"
                  onClick={() => handleDelete(event.id)}
                >
                  🗑
                </button>
              </div>

            </div>
          ))
        ) : (
          <p>Немає подій</p>
        )}
      </div>

      {/* ➕ СОБЫТИЕ */}
      <div className="admin-form">
        <h2>Додати подію</h2>

        <form onSubmit={handleSubmit}>
          <input placeholder="Назва" value={form.title}
            onChange={(e) => setForm({ ...form, title: e.target.value })} />

          <input placeholder="Опис" value={form.description}
            onChange={(e) => setForm({ ...form, description: e.target.value })} />

          <input placeholder="Місто" value={form.location}
            onChange={(e) => setForm({ ...form, location: e.target.value })} />

          <input type="datetime-local" value={form.date}
            onChange={(e) => setForm({ ...form, date: e.target.value })} />

          <input placeholder="Картинка" value={form.image}
            onChange={(e) => setForm({ ...form, image: e.target.value })} />

          <button>Створити</button>
        </form>
      </div>

      {/* 📰 НОВОСТИ */}
      <div className="admin-stats">
        <h2>Новини</h2>

        {news.length > 0 ? (
          news.map(item => (
            <div key={item.id} className="stat-card">
              <div>
                <h3>{item.title}</h3>
                <p>{new Date(item.date).toLocaleDateString()}</p>
              </div>

              <button
                className="delete-btn"
                onClick={() => handleDeleteNews(item.id)}
              >
                🗑
              </button>
            </div>
          ))
        ) : (
          <p>Новин немає</p>
        )}
      </div>

      {/* ➕ НОВОСТЬ */}
      <div className="admin-form">
        <h2>Додати новину</h2>

        <form onSubmit={handleAddNews}>
          <input placeholder="Заголовок" value={newsForm.title}
            onChange={(e) => setNewsForm({ ...newsForm, title: e.target.value })} />

          <textarea placeholder="Текст" value={newsForm.content}
            onChange={(e) => setNewsForm({ ...newsForm, content: e.target.value })} />

          <input type="datetime-local" value={newsForm.date}
            onChange={(e) => setNewsForm({ ...newsForm, date: e.target.value })} />

          <button>Додати</button>
        </form>
      </div>

      {/* ✏️ МОДАЛКА */}
      {editingEvent && (
        <div className="modal-overlay" onClick={() => setEditingEvent(null)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>

            <h2>Редагувати подію</h2>

            <form onSubmit={handleUpdateEvent}>
              <input value={editingEvent.title}
                onChange={(e) =>
                  setEditingEvent({ ...editingEvent, title: e.target.value })} />

              <input value={editingEvent.description}
                onChange={(e) =>
                  setEditingEvent({ ...editingEvent, description: e.target.value })} />

              <input value={editingEvent.location}
                onChange={(e) =>
                  setEditingEvent({ ...editingEvent, location: e.target.value })} />

              <input type="datetime-local" value={editingEvent.date}
                onChange={(e) =>
                  setEditingEvent({ ...editingEvent, date: e.target.value })} />

              <input value={editingEvent.image}
                onChange={(e) =>
                  setEditingEvent({ ...editingEvent, image: e.target.value })} />

              <button>Зберегти</button>
            </form>

            <button className="close-btn" onClick={() => setEditingEvent(null)}>
              Закрити
            </button>

          </div>
        </div>
      )}

    </div>
  );
};

export default Admin;
